mapper.select:
SELECT o.id, o.order_no as orderNo, u1.nickname as buyerNickname, -- 买家昵称 o.buyer_id as buyerId, u1.user_pic as buyerPic, o.seller_id as sellerId, u2.nickname as sellerNickname, -- 卖家昵称 u2.user_pic as sellerPic, o.goods_id as goodsId, o.goods_name as goodsName, o.goods_pic as goodsPic, o.goods_price as goodsPrice, o.goods_num as goodsNum, o.total_amount as totalAmount, o.order_status as orderStatus, o.pay_type as payType, o.refund_status as refundStatus, -- 退款状态 o.refund_amount as refundAmount, -- 退款金额 o.refund_reason as refundReason, o.create_time as createTime, o.update_time as updateTime FROM order_info o LEFT JOIN user u1 ON o.buyer_id = u1.id -- 关联买家表取昵称 LEFT JOIN user u2 ON o.seller_id = u2.id -- 关联卖家表取昵称
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.buyer_id = #{buyerId}
AND o.seller_id = #{sellerId}
AND o.goods_id = #{goodsId}
AND o.order_status = #{orderStatus}
AND o.refund_status = #{refundStatus}
AND o.create_time >= #{startTime}
AND o.create_time <= #{endTime}
ORDER BY o.create_time DESC
